63	function calculateQuotePremium(items: any[], yearsWithMHPCO: number, quoteIndex: number): number {
64	  const basePremium = calculateBasePremium(items);
65	  const itemSurcharges = calculateItemSurcharges(items);
66	  const policyModifiers = calculatePolicyModifiers(basePremium, yearsWithMHPCO, quoteIndex);
67	  return Math.ceil(basePremium + itemSurcharges + policyModifiers + PROCESSING_FEE);
68	}
