70	const DEDUCTIBLE = 100;
71	
72	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
73	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
74	
75	function calculateClaimPayout(damages: any[], policyItems: any[]): number {
76	  return damages.reduce((total, damage) => {
77	    const item = policyItems.find((i: any) => i.type === damage.itemType);
78	    const isHighEnchantment = item && item.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
79	    const reimbursement = isHighEnchantment
80	      ? damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE
81	      : damage.amount;
82	    return total + (reimbursement - DEDUCTIBLE);
83	  }, 0);
84	}
