86	export function processScenario(scenario: any): any {
87	  const results: any[] = [];
88	  const policies: any[] = [];
89	  let quoteCount = 0;
90	  for (const step of scenario.steps) {
91	    if (step.op === "quote") {
92	      const premium = calculateQuotePremium(step.items, scenario.customer.yearsWithMHPCO, quoteCount);
93	      results.push({ premium });
94	      policies.push({ items: step.items });
95	      quoteCount++;
96	    } else if (step.op === "claim") {
97	      const policy = policies[step.policy];
98	      const payout = calculateClaimPayout(step.incident.damages, policy.items);
99	      results.push({ payout });
100	    }
101	  }
102	  return { results };
103	}
